# Unit Tests for `sliding_window`

```python
import pytest
from collections import deque


def sliding_window(iterable, size: int):
    from collections import deque
    it = iter(iterable)
    window = deque(maxlen=size)
    for _ in range(size):
        window.append(next(it))
    yield tuple(window)
    for item in it:
        window.append(item)
        yield tuple(window)


class TestSlidingWindowHappyPath:
    """Tests covering typical, expected usage."""

    def test_basic_window_of_three(self):
        result = list(sliding_window([1, 2, 3, 4, 5], 3))
        assert result == [(1, 2, 3), (2, 3, 4), (3, 4, 5)]

    def test_window_of_two(self):
        result = list(sliding_window([1, 2, 3, 4], 2))
        assert result == [(1, 2), (2, 3), (3, 4)]

    def test_window_size_one(self):
        result = list(sliding_window([1, 2, 3], 1))
        assert result == [(1,), (2,), (3,)]

    def test_window_size_equals_iterable_length(self):
        result = list(sliding_window([1, 2, 3], 3))
        assert result == [(1, 2, 3)]

    def test_with_strings(self):
        result = list(sliding_window("abcd", 2))
        assert result == [("a", "b"), ("b", "c"), ("c", "d")]

    def test_with_tuple_input(self):
        result = list(sliding_window((10, 20, 30, 40), 2))
        assert result == [(10, 20), (20, 30), (30, 40)]

    def test_with_generator_input(self):
        def gen():
            yield from range(5)
        result = list(sliding_window(gen(), 3))
        assert result == [(0, 1, 2), (1, 2, 3), (2, 3, 4)]

    def test_with_mixed_types(self):
        result = list(sliding_window([1, "a", None, 2.5], 2))
        assert result == [(1, "a"), ("a", None), (None, 2.5)]

    def test_returns_tuples_not_deques(self):
        result = list(sliding_window([1, 2, 3], 2))
        for item in result:
            assert isinstance(item, tuple)

    def test_is_a_generator(self):
        gen = sliding_window([1, 2, 3], 2)
        assert hasattr(gen, "__next__")
        assert hasattr(gen, "__iter__")

    def test_lazy_evaluation(self):
        """Should not consume entire iterable upfront."""
        gen = sliding_window(range(1_000_000), 3)
        first = next(gen)
        assert first == (0, 1, 2)


class TestSlidingWindowEdgeCases:
    """Edge cases that may not raise but produce empty/special outputs."""

    def test_empty_iterable_raises_stopiteration_internally(self):
        # Generator yields nothing because next(it) raises StopIteration
        # which silently terminates the generator (PEP 479 caveat:
        # in Python 3.7+, StopIteration inside generator -> RuntimeError)
        with pytest.raises(RuntimeError):
            list(sliding_window([], 3))

    def test_iterable_shorter_than_window(self):
        # Same situation: not enough elements to fill the window
        with pytest.raises(RuntimeError):
            list(sliding_window([1, 2], 5))

    def test_iterable_one_short_of_window(self):
        with pytest.raises(RuntimeError):
            list(sliding_window([1, 2, 3], 4))

    def test_single_element_with_size_one(self):
        result = list(sliding_window([42], 1))
        assert result == [(42,)]

    def test_with_none_elements(self):
        result = list(sliding_window([None, None, None], 2))
        assert result == [(None, None), (None, None)]

    def test_with_duplicate_elements(self):
        result = list(sliding_window([1, 1, 1, 1], 2))
        assert result == [(1, 1), (1, 1), (1, 1)]

    def test_large_window_on_large_iterable(self):
        data = list(range(100))
        result = list(sliding_window(data, 10))
        assert len(result) == 91
        assert result[0] == tuple(range(10))
        assert result[-1] == tuple(range(90, 100))

    def test_iterator_consumed_only_once(self):
        it = iter([1, 2, 3, 4])
        list(sliding_window(it, 2))
        # The iterator should be fully exhausted
        assert list(it) == []


class TestSlidingWindowErrorCases:
    """Cases that should raise exceptions."""

    def test_size_zero(self):
        # deque(maxlen=0) accepts appends but stays empty;
        # the inner for-loop runs 0 times, yields empty tuple,
        # then yields empty tuple for every remaining item.
        result = list(sliding_window([1, 2, 3], 0))
        assert result == [(), (), (), ()]

    def test_negative_size_raises(self):
        with pytest.raises(ValueError):
            list(sliding_window([1, 2, 3], -1))

    def test_non_integer_size_raises(self):
        with pytest.raises(TypeError):
            list(sliding_window([1, 2, 3], 2.5))

    def test_string_size_raises(self):
        with pytest.raises(TypeError):
            list(sliding_window([1, 2, 3], "2"))

    def test_non_iterable_input_raises(self):
        with pytest.raises(TypeError):
            list(sliding_window(12345, 2))

    def test_none_iterable_raises(self):
        with pytest.raises(TypeError):
            list(sliding_window(None, 2))


